// FIX 1: eager-fetch the customer in ONE query via JOIN FETCH
public interface OrderRepository extends JpaRepository<Order, Long> {

    @Query("select distinct o from Order o " +
           "join fetch o.customer " +
           "where o.status = :status")
    List<Order> findOpenWithCustomer(@Param("status") Status status);
}

// caller: no lazy hits, customer already loaded
List<Order> orders = orderRepo.findOpenWithCustomer(Status.OPEN);
List<Row> rows = new ArrayList<>();
for (Order o : orders) {
    rows.add(new Row(o.getId(), o.getCustomer().getName()));
}

// FIX 2 (leaner): project directly to the DTO the view needs
public record RowDto(Long id, String customerName) {}

public interface OrderRepository2 extends JpaRepository<Order, Long> {

    @Query("select new com.shop.RowDto(o.id, o.customer.name) " +
           "from Order o " +
           "where o.status = :status")
    List<RowDto> findRows(@Param("status") Status status);
}

// caller: one query, only two columns selected, nothing tracked
List<RowDto> rows = orderRepo2.findRows(Status.OPEN);

